// Public-facing worker that accepts user requests and forwards them to internal workers for processing
addEventListener("fetch", event => {
  const request = event.request;
  const url = new URL(request.url);
  if (url.pathname === "/") {
    // Forward the request to an internal worker based on the path
    const internalWorker = getInternalWorkerForPath(url.pathname);
    if (!internalWorker) {
      return event.respondWith(new Response("Not found", { status: 404 }));
    }
    return event.respondWith(fetch(`https://${internalWorker}/`, request));
  } else {
    // Handle other requests as needed
  }
});

// Get the internal worker for a given path
function getInternalWorkerForPath(path) {
  const serviceBindings = await KV.get("service-bindings");
  if (!serviceBindings) {
    return null;
  }
  const bindings = JSON.parse(serviceBindings);
  for (const binding of bindings) {
    if (binding.path === path) {
      return binding.worker;
    }
  }
  return null;
}